package uz.ismoilov.cs2livewallpaper;
import android.app.*;import android.os.*;import android.content.*;import android.app.WallpaperManager;import android.view.*;import android.widget.*;import java.util.*;
public class SettingsActivity extends Activity{
 public void onCreate(Bundle b){super.onCreate(b);LinearLayout l=new LinearLayout(this);l.setOrientation(LinearLayout.VERTICAL);l.setPadding(42,60,42,42);l.setBackgroundColor(0xff050b14);TextView t=new TextView(this);t.setText("CS2 Live Wallpaper — Realme GT5\n\nShaharni tanlang va live wallpaperni yoqing.");t.setTextColor(0xffffffff);t.setTextSize(20);l.addView(t);Spinner s=new Spinner(this);String[] cities={"Tashkent","Andijan","Asaka","Fergana","Samarkand"};s.setAdapter(new ArrayAdapter<String>(this,android.R.layout.simple_spinner_dropdown_item,cities));s.setSelection(Arrays.asList(cities).indexOf(WeatherStore.city(this)));l.addView(s);Button save=new Button(this);save.setText("Saqlash va ob-havoni yangilash");l.addView(save);Button set=new Button(this);set.setText("Live Wallpaper sifatida o'rnatish");l.addView(set);TextView note=new TextView(this);note.setTextColor(0xff9fcfff);note.setText("\nEslatma: app iconlari wallpaper dizaynida ko'rinadi. Haqiqiy ilovalar iconlari Android launcher tomonidan alohida chiqadi.");l.addView(note);save.setOnClickListener(v->{WeatherStore.city(this,(String)s.getSelectedItem());WeatherStore.refresh(this);Toast.makeText(this,"Saqlandi",0).show();});set.setOnClickListener(v->{try{startActivity(new Intent(WallpaperManager.ACTION_LIVE_WALLPAPER_CHOOSER));}catch(Exception e){startActivity(new Intent(WallpaperManager.ACTION_CHANGE_LIVE_WALLPAPER));}});setContentView(l);WeatherStore.refresh(this);} }
